// src/pages/Wallet/Withdraw.jsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Loader2 } from 'lucide-react';
import './WalletActions.css';

export default function Withdraw() {
  const navigate = useNavigate();
  const [amount, setAmount] = useState('');
  const [account, setAccount] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleWithdraw = async () => {
    setError('');

    if (!amount || amount <= 0) {
      setError('Enter valid amount');
      return;
    }

    if (!account) {
      setError('Enter bank/UPI details');
      return;
    }

    if (amount < 50) {
      setError('Minimum withdrawal is ₹50');
      return;
    }

    setLoading(true);

    try {
      // 🔥 Replace with backend API
      await new Promise((res) => setTimeout(res, 1500));

      alert(`₹${amount} withdrawal requested`);
      navigate('/wallet');

    } catch (err) {
      setError('Withdrawal failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="wallet-action-container">

      {/* Header */}
      <div className="wallet-action-header">
        <button onClick={() => navigate(-1)}><ArrowLeft /></button>
        <h2>Withdraw Money</h2>
      </div>

      {/* Form */}
      <div className="wallet-card">
        <label>Amount</label>
        <input
          type="number"
          placeholder="₹ Enter amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />

        <label>Bank / UPI ID</label>
        <input
          type="text"
          placeholder="Enter UPI or Bank details"
          value={account}
          onChange={(e) => setAccount(e.target.value)}
        />

        {error && <p className="error">{error}</p>}
      </div>

      {/* Action */}
      <button 
        className="primary-btn" 
        onClick={handleWithdraw}
        disabled={loading}
      >
        {loading ? <Loader2 className="spin" /> : 'Withdraw'}
      </button>

    </div>
  );
}
